  comentarios: string = []
}

function contemPalavraNos Comentarios (p: Postagem, p: Palavra): Palavra {
  for (let i: number; i < p.comentaios.length; i++) {
    // contains testa se uma string ocorre dentro de outra
    if (p.comentaios[i].contains(p)) {
      return p.comentaios[i]
    }
  }
}

class S13 {
  mj: string = ""
  mr: string = ""
}

function mm(kk: string): S13 {
  let sa: S13 = {mj: "", mr: ""}
  for (let i: number = 0; i < kk.length; i++) {
    if (i > (kk.length / 2)) {
      sa.mj = sa.mj + kk[i]
    } else {
      sa.mr = sa.mr + kk[i]
    }
  }
  return sa
}

